package org.apache.commons.math.ode.events;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.ode.events.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math.ode.events.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import org.apache.commons.math.analysis.solvers.UnivariateSolverUtils;
import org.apache.commons.math.analysis.solvers.BrentSolver;
import org.apache.commons.math.analysis.UnivariateFunction;

public class StepDefs {

    private UnivariateFunction function;
    private double tolerance;
    private double r1;
    private double t0;
    private double t1;
    private boolean increasing;
    private double result;
    private Exception caughtException;

    @Given("an event handler for a function g\\(t\\) = \\(t - 90\\) \\* \\(135 - t\\)")
    public void an_event_handler_for_a_function() {
        this.function = new UnivariateFunction() {
            public double value(double t) {
                return (t - 90) * (135 - t);
            }
        };
    }

    @Given("the event detection tolerance is {double}")
    public void the_event_detection_tolerance_is(double tolerance) {
        this.tolerance = tolerance;
    }

    @Given("a previous event at r1 = {double} was accepted at t0 = {double} \\(where g\\(t0\\) is still negative\\)")
    public void a_previous_event_at_r1_accepted_at_t0(double r1, double t0) {
        this.r1 = r1;
        this.t0 = t0;

        // Verify g(t0) is indeed negative
        double g_t0 = function.value(t0);
        assertTrue("g(t0) should be negative, but was: " + g_t0, g_t0 < 0);
    }

    @Given("the logical state indicates the function is increasing \\(positive\\) after the event")
    public void the_logical_state_indicates_the_function_is_increasing_after_the_event() {
        this.increasing = true;
    }

    @When("the event state evaluates a step from t0 to t1 = {double}")
    public void the_event_state_evaluates_a_step_from_t0_to_t1(double t1) {
        this.t1 = t1;

        try {
            // This simulates the step evaluation that should trigger the root finding
            // Attempt to find the root in the range [t0, t1]
            // The issue may occur if the solver receives a range where the function has the same sign at both ends
            BrentSolver solver = new BrentSolver();
            result = solver.solve(100, function, t0, t1);
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the system should recognize the sign change for the next event at r2 = {double}")
    public void the_system_should_recognize_the_sign_change_for_the_next_event(double r2) {
        // The function g(t) = (t - 90) * (135 - t) has roots at t = 90 and t = 135
        // Between t0 (where g(t0) < 0) and t1, there should be a sign change at t = 135
        // Check if the result is near r2 = 135.0
        assertEquals("The root should be found near r2 = " + r2, r2, result, 1.0);
    }

    @Then("the root solver should not fail with \"function values at endpoints do not have different signs\"")
    public void the_root_solver_should_not_fail_with_function_values_at_endpoints_do_not_have_different_signs() {
        assertNull("Root solver should not fail with an exception, but caught: " + 
                  (caughtException != null ? caughtException.getMessage() : "none"), caughtException);
    }

    @Then("the next event should be detected near {double}")
    public void the_next_event_should_be_detected_near(double expected) {
        assertEquals("Event should be detected near " + expected, expected, result, 1.0);
    }
}

